ContainedObjects.LuaScript:
LABEL = "EGG"
LASTTOUCH = nil

function onLoad(savedata)
    if savedata ~= "" then
        state = JSON.decode(savedata)
        LASTTOUCH = state.lasttouch
    end
end

function onSave()
    state = {
        lasttouch = LASTTOUCH
    }
    return JSON.encode(state)
end

function onPickUp(color)
    LASTTOUCH = color
end

